/* ------------------------------------------------------------------ */ /*  Utilities                                                          */ /* ------------------------------------------------------------------ */ function hexToRgb(hex) {
    const h = hex.replace("#", "");
    const bigint = parseInt(h, 16);
    const r = bigint >> 16 & 255;
    const g = bigint >> 8 & 255;
    const b = bigint & 255;
    return `${r},${g},${b}`;
}
function flowProgressWidth(phase) {
    switch(phase){
        case "to_interceptor":
            return "10%";
        case "at_interceptor":
            return "25%";
        case "to_agent":
            return "40%";
        case "at_agent":
            return "55%";
        case "to_ollama":
            return "70%";
        case "at_ollama":
            return "85%";
        case "to_response":
            return "95%";
        case "done":
            return "100%";
        default:
            return "0%";
    }
}
